diff --git a/llvm/lib/Transforms/IPO/SCCP.cpp b/llvm/lib/Transforms/IPO/SCCP.cpp
index d50de34dfa48..704a50ce1798 100644
--- a/llvm/lib/Transforms/IPO/SCCP.cpp
+++ b/llvm/lib/Transforms/IPO/SCCP.cpp
@@ -246,9 +246,21 @@ static bool runIPSCCP(
     for (BasicBlock &BB : F)
       MadeChanges |= Solver.removeNonFeasibleEdges(&BB, DTU, NewUnreachableBB);

-    for (BasicBlock *DeadBB : BlocksToErase)
-      if (!DeadBB->hasAddressTaken())
+    for (BasicBlock *DeadBB : BlocksToErase) {
+      if (!DeadBB->hasAddressTaken()) {
+        // Remove all predecessors to the dead block before deleting it.
+        // changeToUnreachable only removes the block from its successors'
+        // predecessor lists, but doesn't remove the block from its predecessors'
+        // successor lists.
+        SmallVector<BasicBlock *, 8> Preds(predecessors(DeadBB));
+        for (BasicBlock *Pred : Preds) {
+          // Remove the edge from Pred to DeadBB.
+          // This updates the terminator in Pred to no longer have DeadBB as a successor.
+          Pred->getTerminator()->replaceSuccessorWith(DeadBB, nullptr);
+        }
         DTU.deleteBB(DeadBB);
+      }
+    }

     Solver.removeSSACopies(F);
   }
